export const CONVERSATION_DETAIL_NAV = Object.entries(CONVERSATION_DETAIL_ITEMS).map(([pageId, data]) => ({
  pageId,
  label: data.items[0]?.label || pageId.replace(/^conversation-/, ''),
  path: `/conversation/${pageId.replace(/^conversation-/, '')}`,
}))

const CONVERSATION_VIDEO_EXTS = /\.(mp4|webm|mov|ogg)(\?|$)/i
const getConversationImage = (item) => {
  if (item.image && !CONVERSATION_VIDEO_EXTS.test(item.image)) return item.image
  return (item.detailImages || []).find((src) => !CONVERSATION_VIDEO_EXTS.test(src)) || ''
}

export const CONVERSATION_CONTENT_ITEMS = Object.entries(CONVERSATION_DETAIL_ITEMS).flatMap(([pageId, data]) => (
  (data.items || []).map((item, index) => ({
    id: item.contentId || item.label || `${pageId}-${index + 1}`,
    pageId,
    label: item.label || `${pageId}-${index + 1}`,
    item,
    action: item.linkType === 'none'
      ? 'none'
      : item.linkType === 'external' || !!item.externalUrl || (item.href && item.href !== '#')
        ? 'external'
        : 'detail',
    href: item.externalUrl || item.href || '#',
    image: getConversationImage(item),
  }))
))

